function SkillIcon({ skill, onTap, tapped }) {
  return (
    <div
      onClick={() => onTap(skill.id)}
      style={{
        display: "flex", flexDirection: "column", alignItems: "center",
        cursor: "pointer", position: "relative", padding: "4px 2px",
        transform: tapped ? "scale(0.92)" : "scale(1)",
        transition: "transform 0.15s ease",
      }}
    >
      <div style={{ position: "relative", width: 72, height: 72 }}>
        <div style={{
          width: 72, height: 72, borderRadius: 16,
          background: tapped ? "rgba(100,220,100,0.18)" : "rgba(255,255,255,0.06)",
          border: tapped ? "2px solid #4ade80" : "2px solid rgba(255,255,255,0.08)",
          display: "flex", alignItems: "center", justifyContent: "center",
          transition: "all 0.2s ease",
          boxShadow: tapped ? "0 0 16px rgba(74,222,128,0.4)" : "none",
        }}>
          <img src={ICONS[skill.icon]} alt={skill.label}
            style={{ width: 52, height: 52, objectFit: "contain" }} />
        </div>
        <div style={{
          position: "absolute", top: -4, right: -4,
          background: "#4ade80", color: "#0a0a1a",
          fontSize: 10, fontWeight: 800,
          borderRadius: 8, padding: "1px 5px",
          fontFamily: "monospace",
          boxShadow: "0 2px 8px rgba(74,222,128,0.5)",
        }}>
          +{skill.points}
        </div>
      </div>
      <span style={{
        color: "white", fontSize: 11, fontWeight: 500,
        textAlign: "center", marginTop: 6, lineHeight: 1.3,
        maxWidth: 76, fontFamily: "'Nunito', sans-serif",
      }}>
        {skill.label}
      </span>
    </div>
  );
}

