export default function ClassDojo() {
  const [screen, setScreen] = useState("main");
  const [tappedSkills, setTappedSkills] = useState(new Set());
  const [lastTapped, setLastTapped] = useState(null);

  const handleTap = (id) => {
    setLastTapped(id);
    setTappedSkills(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
    setTimeout(() => setLastTapped(null), 300);
  };

  if (screen === "reward") {
    return (
      <div style={{ maxWidth: 390, margin: "0 auto", minHeight: "100vh", background: "#0f0e1a" }}>
        <RewardScreen onBack={() => setScreen("main")} tappedSkills={tappedSkills} onTap={handleTap} />
      </div>
    );
  }

  return (
    <div style={{
      maxWidth: 390, margin: "0 auto", minHeight: "100vh",
      background: "linear-gradient(180deg, #1a1830 0%, #0f0e1a 100%)",
      fontFamily: "'Nunito', sans-serif",
      display: "flex", flexDirection: "column",
    }}>
      {/* Toast banner */}
      <div style={{
        background: "white", borderRadius: 16,
        margin: "12px 12px 8px", padding: "12px 16px",
        display: "flex", alignItems: "center", justifyContent: "space-between",
        boxShadow: "0 4px 20px rgba(0,0,0,0.3)",
      }}>
        <span style={{ fontWeight: 700, fontSize: 16, color: "#1a1a2e" }}>
          +1 for Reading
        </span>
        <button onClick={() => setScreen("reward")} style={{
          width: 40, height: 40, borderRadius: "50%",
          background: "#1a1a2e", border: "none", cursor: "pointer",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 18,
        }}>↺</button>
      </div>

      {/* Skills grid */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(4, 1fr)",
        gap: "16px 6px", padding: "8px 10px", flex: 1, overflowY: "auto",
      }}>
        {screen1Skills.map(skill => (
          <SkillIcon key={skill.id} skill={skill}
            onTap={handleTap} tapped={tappedSkills.has(skill.id)} />
        ))}
      </div>

      {/* Edit skills */}
      <div style={{ padding: "8px 16px" }}>
        <button style={{
          background: "none", border: "none",
          color: "#a78bfa", fontSize: 14, fontWeight: 700,
          cursor: "pointer", display: "flex", alignItems: "center", gap: 6,
          fontFamily: "'Nunito', sans-serif",
        }}>
          💜 Edit skills
        </button>
      </div>

      {/* Give reward button */}
      <div style={{ padding: "8px 16px 32px" }}>
        <button onClick={() => setScreen("reward")} style={{
          width: "100%", background: "linear-gradient(135deg, #7c3aed, #a855f7)",
          border: "none", borderRadius: 30, padding: "16px",
          color: "white", fontSize: 18, fontWeight: 700,
          cursor: "pointer", display: "flex", alignItems: "center",
          justifyContent: "center", gap: 10,
          boxShadow: "0 8px 24px rgba(124,58,237,0.5)",
          fontFamily: "'Nunito', sans-serif",
        }}>
          <span>🏅</span> Give a reward
        </button>
      </div>
    </div>
  );
}
